const meta = $items("Set Reporting Period")
  .all()
  .map((item) => item.json);
const aiOutput = $input.first().json;
const fields = ["output", "text", "response", "answer", "result"];
let html = "";

for (let field of fields) {
  if (aiOutput[field]) {
    html = aiOutput[field];
    break;
  }
}

if (typeof html !== "string") {
  html = JSON.stringify(html);
}

html = html.replace(/```/g, ""); // remove markdown code fences

if (!/<[a-z][\s\S]*>/i.test(html)) {
  // check if it's not a valid HTML
  html = `<pre>${html.replace(/</g, "&lt;").replace(/>/g, "&gt;")}</pre>`; // escape characters and wrap in <pre>
}

const subject = "NovaCart Monthly Financial Standing Report — Month Year";

return [{ json: { ...meta, report_subject: subject, report_html: html } }];

const now = new Date();
const generated_at = now.toISOString();

// Calculate previous month
const previousMonthDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const report_year = previousMonthDate.getFullYear();
const report_month = previousMonthDate.getMonth() + 1; // Months are 0-based in JavaScript

// Month name
const monthNames = [
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];
const report_month_name = monthNames[previousMonthDate.getMonth()];

// Period start and end
const period_start = `${report_year}-${report_month.toString().padStart(2, "0")}-01`;
const period_end = new Date(report_year, report_month, 0)
  .toISOString()
  .split("T")[0]; // Last day of previous month

return [
  {
    json: {
      generated_at,
      report_year,
      report_month,
      report_month_name,
      period_start,
      period_end,
    },
  },
];

const meta = $input.all().map((item) => item.json)[0];

const sessionId = `monthly_finance_report_${String(meta.report_year).padStart(4, "0")}_${String(meta.report_month).padStart(2, "0")}`;

const chatInput = `I need a "Monthly Financial Standing Report" for NovaCart for the month of ${meta.report_month_name} ${meta.report_year} (period: ${meta.period_start} to ${meta.period_end}). Please use the Internal Finance and External Market vector stores, correlate insights, and provide a narrative with tables. The output should be valid HTML only. Also, mention any assumptions or data gaps.`;

return [{ json: { ...meta, sessionId, chatInput, text: chatInput } }];
